// Standalone Lyria music generation for Vision GridAI
// Pattern adapted from t86SwvKbaux2G3o4 (reference workflow)
// Flow: Read script from Supabase → AI analyze via Anthropic → Generate clips via Lyria → Merge + Loop → Upload to Drive

const input = $input.first().json;
const topicId = input.topic_id;
const projectId = input.project_id;

// Step 1: Read script from Supabase
const topicResp = await this.helpers.httpRequest({
  method: 'GET',
  url: `${process.env.SUPABASE_URL}/rest/v1/topics?id=eq.${topicId}&select=script_json,word_count,seo_title`,
  headers: { 'apikey': process.env.SUPABASE_ANON_KEY, 'Authorization': `Bearer ${process.env.SUPABASE_SERVICE_ROLE_KEY}` },
});

const topic = topicResp?.[0];
if (!topic?.script_json) {
  return [{ json: { success: false, error: 'No script found for topic', topic_id: topicId } }];
}

// Extract script text from scenes
const scenes = Array.isArray(topic.script_json) ? topic.script_json : topic.script_json?.scenes || [];
const scriptText = scenes.map(s => s.narration || s.narration_text || '').join(' ');
const wordCount = topic.word_count || scriptText.split(/\s+/).length;
const durationMinutes = Math.ceil(wordCount / 150); // ~150 words/min narration
const clipsNeeded = Math.ceil((durationMinutes * 60) / 30); // 30s per Lyria clip

// Step 2: AI analyze script for music mood via Anthropic
const musicPrompt = [
  'You are a world-class film composer scoring cinematic background music for a YouTube video essay.',
  'Analyze this script and return a music generation profile.',
  '',
  'REQUIREMENTS:',
  '- Film score quality: orchestral strings, emotive piano, atmospheric synth pads',
  '- Dynamic range: soft passages, building tension, emotional swells',
  '- Support narration: stay in mid-low frequency range, leave vocal space clear',
  '- NO lyrics, NO vocals, NO artist name references',
  '- Describe SOUND only: instruments, mood, tempo, energy, texture',
  '',
  `Script: ${wordCount} words, ${durationMinutes} minutes, needs ${clipsNeeded} x 30s clips`,
  '',
  `Script excerpt: ${scriptText.substring(0, 2000)}`,
  '',
  'Return ONLY this JSON (no markdown):',
  '{"genre":"","mood":"","bpm":0,"instruments":"","base_prompt":"","variation_prompts":["","",""],"energy_curve":""}',
].join('\n');

let musicProfile;
try {
  const aiResp = await this.helpers.httpRequest({
    method: 'POST',
    url: 'https://api.anthropic.com/v1/messages',
    headers: { 'x-api-key': process.env.ANTHROPIC_API_KEY, 'anthropic-version': '2023-06-01', 'content-type': 'application/json' },
    body: JSON.stringify({ model: 'claude-3-5-haiku-20241022', max_tokens: 1024, messages: [{ role: 'user', content: musicPrompt }] }),
  });
  const text = aiResp.content?.[0]?.text || '{}';
  try { musicProfile = JSON.parse(text); } catch {
    const m = text.match(/\{[\s\S]*\}/);
    musicProfile = m ? JSON.parse(m[0]) : { base_prompt: 'cinematic orchestral underscore, emotional piano, subtle strings, 80 bpm', variation_prompts: [] };
  }
} catch (e) {
  musicProfile = { base_prompt: 'cinematic orchestral underscore, emotional piano, subtle strings, 80 bpm', variation_prompts: [] };
}

// Step 3: Get GCP token for Lyria
let gcpToken;
try {
  const tokenResp = await this.helpers.httpRequest({ method: 'GET', url: 'http://gcp-token-service:3001/token' });
  gcpToken = tokenResp.token || tokenResp.access_token;
} catch (e) {
  return [{ json: { success: false, error: 'GCP token service unavailable: ' + e.message, topic_id: topicId } }];
}

// Step 4: Generate music clips via Vertex AI Lyria
const gcpProject = process.env.GCP_PROJECT || 'vision-gridai';
const gcpRegion = process.env.GCP_REGION || 'us-central1';
const lyriaUrl = `https://${gcpRegion}-aiplatform.googleapis.com/v1/projects/${gcpProject}/locations/${gcpRegion}/publishers/google/models/lyria-002:predict`;

const prompts = [musicProfile.base_prompt, ...(musicProfile.variation_prompts || [])].filter(Boolean);
const clipPaths = [];

for (let i = 0; i < Math.min(clipsNeeded, prompts.length || 1); i++) {
  const prompt = prompts[i % prompts.length] || musicProfile.base_prompt;
  try {
    const resp = await this.helpers.httpRequest({
      method: 'POST',
      url: lyriaUrl,
      headers: { 'Authorization': `Bearer ${gcpToken}`, 'Content-Type': 'application/json' },
      body: JSON.stringify({ instances: [{ prompt, duration_seconds: 30 }], parameters: { sample_count: 1 } }),
    });

    // Extract audio data and save
    const audioData = resp?.predictions?.[0]?.bytesBase64Encoded;
    if (audioData) {
      const clipPath = `/tmp/production/${topicId}/music_clip_${i}.wav`;
      const { execSync } = require('child_process');
      execSync(`mkdir -p /tmp/production/${topicId}`);
      require('fs').writeFileSync(clipPath, Buffer.from(audioData, 'base64'));
      clipPaths.push(clipPath);
    }
  } catch (e) {
    // Log but continue with other clips
    console.log(`Clip ${i} generation failed: ${e.message}`);
  }

  // Rate limit: wait 5s between clips
  if (i < clipsNeeded - 1) await new Promise(r => setTimeout(r, 5000));
}

if (clipPaths.length === 0) {
  return [{ json: { success: false, error: 'No music clips generated', topic_id: topicId } }];
}

// Step 5: Merge clips + convert to MP3
const { execSync } = require('child_process');
const mergedPath = `/tmp/production/${topicId}/music_merged.mp3`;

try {
  if (clipPaths.length === 1) {
    execSync(`ffmpeg -y -i "${clipPaths[0]}" -c:a libmp3lame -b:a 192k "${mergedPath}"`, { timeout: 30000 });
  } else {
    // Concat all clips
    const concatList = clipPaths.map(p => `file '${p}'`).join('\n');
    require('fs').writeFileSync(`/tmp/production/${topicId}/music_concat.txt`, concatList);
    execSync(`ffmpeg -y -f concat -safe 0 -i /tmp/production/${topicId}/music_concat.txt -c:a libmp3lame -b:a 192k "${mergedPath}"`, { timeout: 60000 });
  }
} catch (e) {
  return [{ json: { success: false, error: 'Music merge failed: ' + e.message, topic_id: topicId } }];
}

// Step 6: Loop to target duration
const targetDuration = durationMinutes * 60;
const loopedPath = `/tmp/production/${topicId}/music_final.mp3`;
try {
  execSync(`ffmpeg -y -stream_loop -1 -i "${mergedPath}" -t ${targetDuration} -c:a libmp3lame -b:a 192k "${loopedPath}"`, { timeout: 60000 });
} catch (e) {
  // If loop fails, use merged as-is
  execSync(`cp "${mergedPath}" "${loopedPath}"`);
}

return [{ json: {
  success: true,
  topic_id: topicId,
  method: 'lyria_generation',
  model: 'lyria-002',
  clips_generated: clipPaths.length,
  clips_needed: clipsNeeded,
  music_path: loopedPath,
  duration_target: targetDuration,
  music_profile: musicProfile,
  duck_volume: input.short_form ? '0.08' : '0.12',
} }];
